#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e6+5;
struct Trie{int fail,son[30],ed,res;}t[N];
int m,n,id[N],Cnt=1,Ans[N],in[N];
string s[N];map<string,int> mp;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void BuildTrie(string str,int id){//建树
    int now=1;//从根开始跑
    for(char c:str){
        if(!t[now].son[c-'a'])
            t[now].son[c-'a']=(++Cnt);
        now=t[now].son[c-'a'];//往下跳
    }t[now].ed=id;return;//权值增加
}
void CountFail(){//求失配指针
    queue<int> q;//新建队列跑 BFS
    while(!q.empty())q.pop();//清空队列
    for(int i=0;i<26;i++)t[0].son[i]=1;//预设
    t[1].fail=0;//根没有失配指针
    q.push(1);//从根出发开始匹配
    while(!q.empty()){//开始遍历队列搞 BFS
        int u=q.front();q.pop();//取队头
        for(int i=0;i<26;i++){//枚举每种字符的子节点
            if(t[u].son[i])//存在这个儿子，不是空节点
                t[t[u].son[i]].fail=t[t[u].fail].son[i],
                //fail 值即为当前节点的 fail 的对应字符儿子
                in[t[t[u].son[i]].fail]++,//更新入度
                q.push(t[u].son[i]);//也给搞到队列里头去
            else //否则不存在这个儿子，里边是空的
                t[u].son[i]=t[t[u].fail].son[i];
                //那么这个儿子更新为当前节点的 fail 的对应字符儿子
        }
    }return;//于是所有的 fail 就都求完啦
}
void SolveACAM(string str){
    int now=1;//从根开始跳
    for(char c:str)//遍历字符串中所有字符
        now=t[now].son[c-'a'],//沿着字符往下跳
        t[now].res++;//打上标记
    return;//解决了，现在只需要等拓扑
}
void TopoSort(){//拓扑优化
    queue<int> q;//新建队列跑拓扑
    while(!q.empty())q.pop();//清空队列
    for(int i=1;i<=Cnt;i++)//遍历所有点
        if(!in[i])q.push(i);//入度为 0 则塞进队列
    while(!q.empty()){
        int u=q.front();q.pop();//取队头
        Ans[t[u].ed]=t[u].res;//存储答案
        int to=t[u].fail;in[to]--;//连边 Fail 并减少入度
        t[to].res+=t[u].res;//更新 Fail 的答案
        if(!in[to])q.push(to);//迭代
    }return;//优化完毕！
}
int main(){
    m=read();//读入
    for(int i=1;i<=m;i++){
        string str;cin>>str;//读入
        s[0]+=str+'#';//论文
        if(!mp[str]){
            mp[str]=(++n),s[n]=str;
            BuildTrie(s[n],n);//建树
        }id[i]=mp[str];//判重
    }CountFail();//求失配指针
    SolveACAM(s[0]);//对应去处理
    TopoSort();//拓扑优化
    for(int i=1;i<=m;i++)cout<<Ans[id[i]]<<"\n";//输出
    return 0;
}
